using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1) GetTypeInfo<T>() — strongly-typed metadata, no cast needed
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> → Type = {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Ada", 36), personInfo);
Console.WriteLine($"  Serialized: {json}");

Person? deserialized = JsonSerializer.Deserialize(json, personInfo);
Console.WriteLine($"  Round-tripped: {deserialized}");

// 2) TryGetTypeInfo<T>() — probe without throwing
//    Person is resolvable → true
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? info))
    Console.WriteLine($"\nTryGetTypeInfo<Person> → found ({info!.Type.Name})");
else
    Console.WriteLine("\nTryGetTypeInfo<Person> → not found");

// Build options that have NO resolver at all → metadata is unavailable
var empty = new JsonSerializerOptions { TypeInfoResolver = null };
empty.MakeReadOnly();              // lock so we can query safely

if (empty.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? missing))
    Console.WriteLine($"TryGetTypeInfo<Person> (no resolver) → found ({missing!.Type.Name})");
else
    Console.WriteLine("TryGetTypeInfo<Person> (no resolver) → not found (no exception!)");

public record Person(string Name, int Age);

